@event.receive("Boot")
def on_receive3():
    global first_boot_done
    global mos_cursor_cursor, mos_system_homelogo, mos_timer_appicon, mos_cursor_mode, mos_messaging_appicon, mos_system_version, mos_timer_timerset_, mos_timer_timer, mos_guess_appicon, mos_guess_gamechosen, mos_guess_number, mos_guess_numberguessed_, mos_guess_guess, mos_guess_chances, mos_messaging_message, mos_messaging_receivedmessage, mos_dino_appicon, mos_dino_dino, mos_dino_dinoinair_, mos_dino_cactus, mos_dino_obstacleexists_, mos_system_powericon, mos_dino_ground, mos_system_homebackgroundcolor, mos_system_wifiservices, mos_messaging_messagereceiver, mos_system_homebackground, mos_weather_appicon, mos_doodle_appicon, mos_doodle_doodling_, mos_doodler_pen, mos_doodler_brushcolor, mos_system_wifissid, mos_system_wifipassword, mos_keyboard_letters, mos_keyboard_word, mos_keyboard_candidate, mos_settings_appicon, mos_cloud_user, mos_cloud_password, mos_cloud_appicon, mos_cloud_accountvalid_, mos_admin_row, mos_admin_column, mos_admin_input
    
    # 1. Clean the OS state on every boot/reboot
    mos_cursor_mode = "OFF"
    cyberpi.console.set_font(12)
    mos_cursor_cursor.delete()

    # 2. Check if this is a reboot (True) or the very first boot (False)
    if first_boot_done == True:
        # --- WAKING UP FROM SHUT OFF (SOFT BOOT) ---
        cyberpi.console.clear()
        cyberpi.display.show_label("Checking Wi-Fi...", 12, "center", index= 0)
        
        # Give Wi-Fi up to 5 seconds to connect
        wait_time = 0
        while not cyberpi.wifi.is_connect() and wait_time < 5:
            time.sleep(0.5)
            wait_time += 0.5
            
        if cyberpi.wifi.is_connect():
            time.sleep(3) # Extra buffer for the internet to fully route
            
            try:
                # The exact URL from your dummy block!
                cyberpi.cloud.sheet_connect("https://docs.google.com/spreadsheets/d/1Le2InbL9Q9RN5GjOdhk8W9CiqGafpmbuhlaItQ4kLpk/edit?gid=0#gid=0")
                
                cyberpi.console.clear()
                cyberpi.display.show_label("Would you like to sign in(Requires Network)", 12, "center", index= 0)
                cyberpi.display.show_label("Hold A: Yes | B: No", 12, "bottom_mid", index= 1)
                
                while not (cyberpi.controller.is_press('a') or cyberpi.controller.is_press('b')):
                    pass

                cyberpi.console.clear()
                if cyberpi.controller.is_press('a'):
                    cyberpi.broadcast_and_wait("Start Syncing")
                else:
                    cyberpi.display.show_label("Not Signed In", 12, "bottom_mid", index= 1)
                    
            except Exception as e:
                # Safely catches a crash if the Google Sheet rejects the connection
                cyberpi.console.clear()
                cyberpi.display.show_label("Cloud Sync Failed.", 12, "center", index= 0)
                cyberpi.display.show_label("Booting Offline Mode.", 12, "bottom_mid", index= 1)
                time.sleep(2)
        else:
            cyberpi.console.clear()
            cyberpi.display.show_label("No Wi-Fi Found.", 12, "center", index= 0)
            cyberpi.display.show_label("Booting Offline Mode.", 12, "bottom_mid", index= 1)
            time.sleep(2)
            
        # Jump straight back to the OS without the music/logo!
        cyberpi.console.clear()
        cyberpi.display.show_label("Welcome back to MellorsOS", 12, "center", index= 0)
        time.sleep(1)
        cyberpi.console.clear()
        cyberpi.broadcast("Show Apps")
            
    else:
        # --- VERY FIRST POWER ON (HARD BOOT) ---
        first_boot_done = True
        
        # Play the intro logo and music
        time.sleep(1)
        cyberpi.display.set_brush(212, 0, 255)
        cyberpi.display.show_label(str('MellorsOS ') + str(mos_system_version), 16, "center", index= 0)
        cyberpi.audio.play_music(49, 1)
        cyberpi.audio.play_music(51, 0.25)
        cyberpi.audio.play_music(56, 0.25)
        
        cyberpi.display.set_brush(255, 255, 255)
        cyberpi.display.show_label("A to Start", 12, "top_mid", index= 2)
        cyberpi.display.show_label(str(cyberpi.get_battery()) + str('%'), 16, "top_right", index= 3)
        cyberpi.display.set_brush(255, 255, 255)
        
        # Wait for user to dismiss
        while not cyberpi.controller.is_press('a'):
            pass

        # Load the OS
        cyberpi.display.show_label("Welcome to MellorsOS", 12, "center", index= 0)
        time.sleep(1)
        cyberpi.console.clear()
        cyberpi.broadcast("Show Apps")

