    global mos_cursor_cursor, mos_system_homelogo, mos_timer_appicon, mos_cursor_mode, mos_messaging_appicon, mos_system_version, mos_timer_timerset_, mos_timer_timer, mos_guess_appicon, mos_guess_gamechosen, mos_guess_number, mos_guess_numberguessed_, mos_guess_guess, mos_guess_chances, mos_messaging_message, mos_messaging_receivedmessage, mos_dino_appicon, mos_dino_dino, mos_dino_dinoinair_, mos_dino_cactus, mos_dino_obstacleexists_, mos_system_powericon, mos_dino_ground, mos_system_homebackgroundcolor, mos_system_wifiservices, mos_messaging_messagereceiver, mos_system_homebackground, mos_weather_appicon, mos_doodle_appicon, mos_doodle_doodling_, mos_doodler_pen, mos_doodler_brushcolor, mos_system_wifissid, mos_system_wifipassword, mos_keyboard_letters, mos_keyboard_word, mos_keyboard_candidate, mos_settings_appicon, mos_cloud_user, mos_cloud_password, mos_cloud_appicon, mos_cloud_accountvalid_, mos_admin_row, mos_admin_column, mos_admin_input
    
    # Check if the cursor is clicking the app icon
    if mos_guess_appicon.is_touch(mos_cursor_cursor):
        mos_cursor_mode = "OFF"
        cyberpi.broadcast("Hide All Apps")
        cyberpi.display.show_label("Mellors Guess Number Game", 12, "center", index= 0)
        time.sleep(1)
        mos_guess_gamechosen = "NO"
        cyberpi.console.clear()
        
        while True:
            cyberpi.console.println("Right: 1-100")
            cyberpi.console.println("Down: 1-500")
            cyberpi.console.println("Up: 1-1000")
            while not mos_guess_gamechosen == 'YES':
                if cyberpi.controller.is_press('right'):
                    mos_guess_gamechosen = "YES"
                    mos_guess_chances = 6
                    mos_guess_number = round(random.randint(1, 100))
                if cyberpi.controller.is_press('down'):
                    mos_guess_gamechosen = "YES"
                    mos_guess_chances = 11
                    mos_guess_number = round(random.randint(1, 500))
                if cyberpi.controller.is_press('up'):
                    mos_guess_gamechosen = "YES"
                    mos_guess_chances = 20
                    mos_guess_number = round(random.randint(1, 1000))
            
            cyberpi.console.clear()
            mos_guess_guess = 0
            mos_guess_numberguessed_ = "NO"
            while not (mos_guess_numberguessed_ == 'YES' or mos_guess_chances < 1):
                cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                if cyberpi.controller.is_press('up'):
                    mos_guess_guess = mos_guess_guess + 1
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('down'):
                    mos_guess_guess = mos_guess_guess + -1
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('right'):
                    mos_guess_guess = mos_guess_guess + 10
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('left'):
                    mos_guess_guess = mos_guess_guess + -10
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('a'):
                    mos_guess_guess = mos_guess_guess + 100
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('b'):
                    mos_guess_guess = mos_guess_guess + -100
                    cyberpi.display.show_label(mos_guess_guess, 12, "center", index= 0)
                    cyberpi.display.show_label(str(mos_guess_chances) + str(' Chances left'), 12, "bottom_mid", index= 1)
                    time.sleep(0.1)
                if cyberpi.controller.is_press('middle'):
                    if mos_guess_guess == mos_guess_number:
                        mos_guess_numberguessed_ = "YES"
                    else:
                        if mos_guess_number > mos_guess_guess:
                            cyberpi.display.show_label(str('Greater than ') + str(mos_guess_guess), 12, "top_mid", index= 7)
                            mos_guess_chances = mos_guess_chances + -1
                        else:
                            cyberpi.display.show_label(str('Less than ') + str(mos_guess_guess), 12, "top_mid", index= 7)
                            mos_guess_chances = mos_guess_chances + -1
            
            cyberpi.console.clear()
            if mos_guess_guess == mos_guess_number:
                cyberpi.display.show_label("YES SIR", 12, "center", index= 2)
            else:
                cyberpi.display.show_label("You Suck", 12, "center", index= 2)
                cyberpi.display.show_label(str('The number was ') + str(mos_guess_number), 12, "bottom_mid", index= 0)
            
            cyberpi.console.println("Click A to Exit")
            while not cyberpi.controller.is_press('a'):
                pass
            
            cyberpi.console.clear()
            cyberpi.broadcast("Show Apps")
            cyberpi.stop_this()

